(function(){const t=document.getElementById("contact-modal");t&&(document.querySelectorAll('[data-open-modal="contact-modal"]').forEach(function(e){e.addEventListener("click",function(){if(typeof t.showModal=="function"){t.showModal();return}t.setAttribute("open","")})}),t.querySelectorAll("[data-close-modal]").forEach(function(e){e.addEventListener("click",function(){t.close()})}),t.addEventListener("click",function(e){e.target===t&&t.close()}))})();
